exercises.solution_code:
#include <cmath>
#include <iostream>
#include <string>

std::string classify(int n)
{
    return n < 0 ? "negative" : n > 0 ? "positive" : "zero";
}

int main()
{
    int n;
    double a, b;
    std::cin >> n >> a >> b;

    std::cout << "Classification: " << classify(n) << '\n';

    constexpr double eps = 1e-9;
    bool equal = std::abs(a - b) <= eps * std::max(1.0, std::max(std::abs(a), std::abs(b)));
    std::cout << "Equal: " << (equal ? "true" : "false") << '\n';

    return 0;
}

