#include <iostream>

int main()
{
    int s1, s2, s3, s4, s5;
    std::cin >> s1 >> s2 >> s3 >> s4 >> s5;

    int pass = 0;
    int fail = 0;
    int sum  = s1 + s2 + s3 + s4 + s5;

    if (s1 >= 60) ++pass; else fail++;
    if (s2 >= 60) ++pass; else fail++;
    if (s3 >= 60) ++pass; else fail++;
    if (s4 >= 60) ++pass; else fail++;
    if (s5 >= 60) ++pass; else fail++;

    std::cout << "Pass: "      << pass      << '\n';
    std::cout << "Fail: "      << fail      << '\n';
    std::cout << "Average: "   << sum / 5   << '\n';
    std::cout << "Remainder: " << sum % 5   << '\n';

    return 0;
}
